    val specialCombinations: Map<Set<String>, String> = mapOf(
        setOf("relaxaurus", "sparkit") to "relaxaurus_lux",
        setOf("surfent", "dumud") to "surfent_terra",
        setOf("reptyro", "foxcicle") to "reptyro_cryst",
